var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"마에스트로 네퀴티아, 현 공간상에서 식별 신호가 소멸했습니다!","JPN":"マエストロ・ネキティア、現空間上での識別信号が消滅しました！","ENG":"Maestra Nequitia’s signal has extinguished in the current area!","TWN":"指揮家 莉奎蒂亞，現在空間上看不到她的識別訊號！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"메이즈 전대, 카멜롯 전대는 현재 도주한 최고 단원들을 추격 중입니다!","JPN":"メイズ戦隊、キャメロット戦隊は現在逃走した首席奏者を追っています！","ENG":"Elite Members are on the run, Maze Division and Camelot Division are currently in pursuit!","TWN":"梅茲戰隊、卡梅羅戰隊正在追擊逃逸的團員！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"하아……. 하아…….","JPN":"はあ……はあ……","ENG":"*Huff… Huff...*","TWN":"呼呼……呼呼……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"후우, 해치우고 나니까 이제 좀 머리가 개운해지네. 만만치 않은 녀석이었어.","JPN":"ふう、やっつけたら頭がすっきりしたね。手ごわい相手だった。","ENG":"Ha... It feels so good now that it’s finally over. That was a rough opponent.","TWN":"呼～清理乾淨後整個清爽多了！那傢伙真不好對付！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"그럴 수밖에. 네퀴티아는 그림자 중에서도 <color=#ffd34c>데모고르곤</color>으로 불리는 개체였으니까.","JPN":"当たり前だよ。ネキティアはシャドウの中でも<color=#ffd34c>デモゴルゴン</color>として呼ばれる個体だったから。","ENG":"Of course. Even amongst the Shadows, Nequitia is called the <color=#ffd34c>Demogorgon</color>.","TWN":"那是當然的囉，即便同為暗影，但莉奎蒂亞可是被歸類為<color=#ffd34c>魔神</color>呢！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"데모…… 뭐?","JPN":"デモ……なんだって？","ENG":"Demo... What?","TWN":"魔……魔什麼？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"……특별히 오래된 그림자들을 부르는 말이야. 성야의 살인마 놀이에 나오는 그림자처럼.","JPN":"……特に長く生き延びているシャドウのことだよ。聖夜の殺人鬼遊びに出てくるシャドウのようにね。","ENG":"...It’s something only the most ancient Shadows are called. Like the Shadow from the game, Killer of the Holy Night.","TWN":"……這是特別針對古老暗影的稱呼，就像聖夜的嫌疑犯遊戲裡的暗影一樣。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"어? 모르스 말이야?","JPN":"え？　モールスのこと？","ENG":"Oh? Are you talking about Mors?","TWN":"喔？你說莫爾斯喔？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"에이, 그거 그냥 겁 많은 신입들 놀리려고 지어낸 얘기잖아.","JPN":"いや、それって臆病な新人をビビらせようと作った話でしょ？","ENG":"Oh, come on. You just made that up to scare the newbies.","TWN":"拜託～那只是用來嚇唬膽小新人而捏造的故事吧！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"대외적으로는. 관리국 내부에서도 대부분은 그렇게 알고 있을 거야.","JPN":"対外的にはね。管理局の中でも大半はそうだと思っているはずだよ。","ENG":"That is the official explanation anyways. Most members of the Administration believe it too.","TWN":"那是對外的說法，管理局內部大部分也都知道這件事。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"그보다 스승님, 네퀴티아는 정말 소멸한 겁니까?","JPN":"それより師匠、ネキティアは本当に消滅したんでしょうか？","ENG":"More importantly, Master, is Nequitia really dead?","TWN":"不過師父，莉奎蒂亞真的死了嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"확신하기엔 아직 이르다. 핵을 파괴하는 감각이 다른 것들과 달랐어.","JPN":"確信するにはまだ早い。核を破壊したときの感じが他のシャドウとは違った。","ENG":"It’s too early to be sure. Destroying that core felt different from usual.","TWN":"現在還言之過早，破壞核心時的感覺不太一樣。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"함교, 지금 바로……","JPN":"艦橋、今すぐ……","ENG":"Bridge, now...","TWN":"艦橋，現在立刻……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":" 음?","JPN":" うむ？","ENG":" Huh?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"몽타뉴? 후방으로 이송된 거 아니었어?","JPN":"モンターニュ？　後方に運ばれたんじゃなかったの？","ENG":"Montagne? Wasn’t she transferred to the rear?","TWN":"蒙塔妮？她不是已經被護送到後方嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"손에 들고 있는 그건…… 설마 카르데나스 전대장님의……","JPN":"手に持っているそれは……まさかカルデナス戦隊長の……","ENG":"In her arms... Isn't it... Commander Cardenas...","TWN":"她手裡抱著的……難道是卡特納斯戰隊長的……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};